import boto3
import json
from botocore.exceptions import ClientError
import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class SecureSQSPublisher:
    def __init__(self, queue_url, region_name='us-east-1'):
        """
        Initialize SQS publisher with secure configurations
        """
        try:
            # Use boto3 client with secure configuration
            self.sqs_client = boto3.client(
                'sqs',
                region_name=region_name,
                # Use IAM roles instead of hardcoded credentials
                # Credentials are automatically handled by boto3
            )
            self.queue_url = queue_url
        except Exception as e:
            logger.error(f"Failed to initialize SQS client: {e}")
            raise

    def send_user_data_message(self, user_data, message_attributes=None):
        """
        Send user data message to SQS queue with PII handling
        """
        try:
            # Validate input data
            if not user_data or not isinstance(user_data, dict):
                raise ValueError("Invalid user data provided")
            
            # Create message body with PII data
            message_body = {
                'user_id': user_data.get('user_id'),
                'email': user_data.get('email'),
                'phone': user_data.get('phone'),
                'address': user_data.get('address'),
                'timestamp': user_data.get('timestamp', self._get_timestamp())
            }
            
            # Prepare message attributes
            attributes = message_attributes or {}
            
            # Send message to SQS
            response = self.sqs_client.send_message(
                QueueUrl=self.queue_url,
                MessageBody=json.dumps(message_body),
                MessageAttributes=attributes,
                # Use message deduplication for FIFO queues if needed
                # MessageDeduplicationId='unique-id'  # Uncomment if FIFO
            )
            
            logger.info(f"Message sent successfully. MessageId: {response['MessageId']}")
            return response
            
        except ClientError as e:
            logger.error(f"SQS ClientError: {e}")
            raise
        except Exception as e:
            logger.error(f"Failed to send message: {e}")
            raise

    def _get_timestamp(self):
        """Generate timestamp for message"""
        from datetime import datetime
        return datetime.utcnow().isoformat()

